<?php $pageTitle='إدارة الأخبار'; include __DIR__.'/includes/header.php'; $pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST' && adminTableExists($pdo,'posts')){ $id=(int)($_POST['id']??0); $data=[trim($_POST['title_ar']),trim($_POST['title_en']),trim($_POST['summary_ar']),trim($_POST['summary_en']),trim($_POST['content_ar']),trim($_POST['content_en']),$_POST['status']??'draft'];
if($id){$pdo->prepare('UPDATE posts SET title_ar=?,title_en=?,summary_ar=?,summary_en=?,content_ar=?,content_en=?,status=?,updated_at=NOW() WHERE id=?')->execute([...$data,$id]);}
else{$pdo->prepare('INSERT INTO posts (title_ar,title_en,summary_ar,summary_en,content_ar,content_en,status,published_at) VALUES (?,?,?,?,?,?,?,NOW())')->execute($data);} }
$items=adminTableExists($pdo,'posts')?adminFetchAll($pdo,'SELECT * FROM posts ORDER BY published_at DESC'):[]; ?>
<div class="container-fluid"><h1 class="h4">إدارة الأخبار</h1><form method="post" class="card card-body mb-3"><div class="row g-2"><div class="col"><input name="title_ar" class="form-control" placeholder="عنوان عربي" required></div><div class="col"><input name="title_en" class="form-control" placeholder="Title EN" required></div><div class="col"><select name="status" class="form-select"><option value="draft">draft</option><option value="published">published</option></select></div><div class="col-auto"><button class="btn btn-primary">إضافة خبر</button></div></div></form>
<table class="table table-bordered table-sm"><tr><th>#</th><th>العنوان</th><th>الحالة</th><th>التاريخ</th></tr><?php foreach($items as $i):?><tr><td><?php echo $i['id'];?></td><td><?php echo escape($i['title_ar']);?></td><td><?php echo escape($i['status']);?></td><td><?php echo escape($i['published_at']);?></td></tr><?php endforeach;?></table></div>
<?php include __DIR__.'/includes/footer.php'; ?>
